mapper.select:
(
SELECT CUST1_CD,CUST1_NM,acct_cd,acct_nm,par_acct_cd parAcctCd,par_acct_nm parAcctNm, is_leaf as leaf,'1' as to_add  FROM ${dataIntegration}.VIEW_HSP_FEE_ACCOUNT
MINUS
SELECT CUST1_CD,CUST1_NM,acct_cd,acct_nm,acct_par_cd parAcctCd,acct_par_nm parAcctNm,leaf,'1' as to_add FROM subject_info where year = #{year}
)
union
(
SELECT CUST1_CD,CUST1_NM,acct_cd,acct_nm,acct_par_cd parAcctCd,acct_par_nm parAcctNm,leaf,'2' as to_add  FROM subject_info where year = #{year}
MINUS
SELECT CUST1_CD,CUST1_NM,acct_cd,acct_nm,par_acct_cd parAcctCd,par_acct_nm parAcctNm,is_leaf as leaf,'2' as to_add  FROM ${dataIntegration}.VIEW_HSP_FEE_ACCOUNT
)

mapper.update:
update subject_info
acct_cd = #{subjectInfo.acctCd}, acct_nm = #{subjectInfo.acctNm}, cust1_cd = #{subjectInfo.cust1Cd}, cust1_nm = #{subjectInfo.cust1Nm}, acct_par_cd = #{subjectInfo.acctParCd}, acct_par_nm = #{subjectInfo.acctParNm}, control_level = #{subjectInfo.controlLevel}, erp_acct_cd = #{subjectInfo.erpAcctCd}, erp_acct_nm = #{subjectInfo.erpAcctNm}, leaf = #{subjectInfo.leaf}, year = #{subjectInfo.year}
where id = #{subjectInfo.id}
